        @{ day = "3"; meals = @{ ar = "إفطار + عشاء"; en = "Breakfast + Dinner"; es = "Desayuno + Cena"; it = "Colazione + Cena"; pt = "Café da manhã + Jantar" }; description = @{ ar = "جولة سوق التوابل والبوسفور بالمركب نهاراً، وزيارة تقسيم والغالاطا، يليه الانتقال للمطار للطيران مباشرة إلى كابادوكيا والمبيت."; en = "Spice Bazaar tour and Bosphorus boat cruise during the day, visit Taksim and Galata, then transfer to airport for direct flight to Cappadocia, overnight."; es = "Recorrido del Bazar de las Especias y paseo en barco por el Bósforo, visita a Taksim y Gálata, luego traslado al aeropuerto para vuelo directo a Capadocia, alojamiento."; it = "Giro del Bazar delle Spezie e crociera in barca sul Bosforo, visita a Taksim e Galata, poi trasferimento in aeroporto per il volo diretto per la Cappadocia, pernottamento."; pt = "Tour do Bazar de Especiarias e cruzeiro de barco pelo Bósforo, visita a Taksim e Gálata, depois transfer para o aeroporto para voo direto para a Capadócia, pernoite." } }
        @{ day = "4"; meals = @{ ar = "إفطار + عشاء"; en = "Breakfast + Dinner"; es = "Desayuno + Cena"; it = "Colazione + Cena"; pt = "Café da manhã + Jantar" }; description = @{ ar = "جولة الوديان في كابادوكيا (جوريم، أواتش حصار، وادي الحب، والمدينة تحت الأرض)."; en = "Valleys tour in Cappadocia (Göreme, Uçhisar, Love Valley, underground city)."; es = "Recorrido por los valles de Capadocia (Göreme, Uçhisar, Valle del Amor, ciudad subterránea)."; it = "Giro delle valli in Cappadocia (Göreme, Uçhisar, Valle dell'Amore, città sotterranea)."; pt = "Passeio pelos vales da Capadócia (Göreme, Uçhisar, Vale do Amor, cidade subterrânea)." } }
        @{ day = "5"; meals = @{ ar = "إفطار + عشاء"; en = "Breakfast + Dinner"; es = "Desayuno + Cena"; it = "Colazione + Cena"; pt = "Café da manhã + Jantar" }; description = @{ ar = "النقل إلى المطار للطيران من كابادوكيا إلى إزمير، النقل للفندق في كوشاداسي."; en = "Transfer to airport for flight from Cappadocia to Izmir, transfer to hotel in Kuşadası."; es = "Traslado al aeropuerto para volar de Capadocia a Esmirna, traslado al hotel en Kuşadası."; it = "Trasferimento in aeroporto per il volo dalla Cappadocia a Smirne, trasferimento in hotel a Kuşadası."; pt = "Transfer para o aeroporto para voo da Capadócia para Esmirna, transfer para o hotel em Kuşadası." } }
        @{ day = "6"; meals = @{ ar = "إفطار + عشاء"; en = "Breakfast + Dinner"; es = "Desayuno + Cena"; it = "Colazione + Cena"; pt = "Café da manhã + Jantar" }; description = @{ ar = "رحلة يوم كامل بالسيارة من كوشاداسي لزيارة مدرجات باموكالي وآثار هيرابوليس والعودة لكوشاداسي."; en = "Full-day trip by car from Kuşadası to visit the Pamukkale travertines and Hierapolis ruins, returning to Kuşadası."; es = "Excursión de día completo en coche desde Kuşadası para visitar los travertinos de Pamukkale y las ruinas de Hierápolis, regreso a Kuşadası."; it = "Gita di un giorno intero in auto da Kuşadası per visitare i travertini di Pamukkale e le rovine di Hierapolis, ritorno a Kuşadası."; pt = "Viagem de dia inteiro de carro de Kuşadası para visitar os travertinos de Pamukkale e as ruínas de Hierápolis, retorno a Kuşadası." } }
        @{ day = "7"; meals = @{ ar = "إفطار + عشاء"; en = "Breakfast + Dinner"; es = "Desayuno + Cena"; it = "Colazione + Cena"; pt = "Café da manhã + Jantar" }; description = @{ ar = "جولة آثار أفسس الرومانية، وبيت مريم العذراء، ومصنع الجلود وعرض الأزياء."; en = "Tour of the Roman ruins of Ephesus, House of the Virgin Mary, leather factory, and fashion show."; es = "Recorrido por las ruinas romanas de Éfeso, Casa de la Virgen María, fábrica de cuero y desfile de moda."; it = "Giro delle rovine romane di Efeso, Casa della Vergine Maria, conceria e sfilata di moda."; pt = "Tour das ruínas romanas de Éfeso, Casa da Virgem Maria, fábrica de couro e desfile de moda." } }
        @{ day = "8"; meals = @{ ar = "إفطار"; en = "Breakfast"; es = "Desayuno"; it = "Colazione"; pt = "Café da manhã" }; description = @{ ar = "النقل للمطار للطيران من إزمير عودة إلى إسطنبول والمبيت."; en = "Transfer to airport for flight from Izmir back to Istanbul, overnight."; es = "Traslado al aeropuerto para volar de Esmirna de regreso a Estambul, alojamiento."; it = "Trasferimento in aeroporto per il volo da Smirne di ritorno a Istanbul, pernottamento."; pt = "Transfer para o aeroporto para voo de Esmirna de volta a Istambul, pernoite." } }
        @{ day = "9"; meals = @{ ar = "إفطار"; en = "Breakfast"; es = "Desayuno"; it = "Colazione"; pt = "Café da manhã" }; description = @{ ar = "التوصيل لمطار إسطنبول للمغادرة النهائية."; en = "Transfer to Istanbul Airport for final departure."; es = "Traslado al aeropuerto de Estambul para la salida final."; it = "Trasferimento all'aeroporto di Istanbul per la partenza finale."; pt = "Transfer para o aeroporto de Istambul para partida final." } }
